INSERT INTO show (id, title, seasons_count, episodes_count) VALUES ('958661e6-226c-5117-9318-5e3265598767', $$Stranger Things$$, 5, 42);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('f0f21e77-e689-54af-a568-b9dd658f48f3', '958661e6-226c-5117-9318-5e3265598767', 1, 1, 1, $$Chapter One: The Vanishing of Will Byers$$, $$On November 6, 1983, in Hawkins, Indiana, a scientist is attacked by an unseen creature at a U.S. government laboratory. 12-year-old Will Byers encounters the creature and mysteriously vanishes while cycling home from a ''Dungeons & Dragons'' session with his friends Mike Wheeler, Dustin Henderson and Lucas Sinclair. The following day, Will's single mother Joyce Byers reports his disappearance to the police chief Jim Hopper, who starts a search but assures Joyce that almost all missing children are quickly found. The lab's director, Dr. Martin Brenner, investigates an organic substance oozing from the lab's basement, claiming that "the girl" cannot have gone far. A nervous young girl wearing a hospital gown wanders into a local diner. The owner, Benny, finds a tattoo of "011" on her arm and learns that her name is Eleven. Brenner, monitoring the phone lines, sends agents to the diner after Benny calls social services. The agents kill Benny, but Eleven manages to escape using telekinetic abilities. Joyce's phone short circuits after receiving a mysterious phone call that she believes is from Will. While searching for Will in the woods, Mike, Dustin, and Lucas come across Eleven.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('8f01c6aa-e147-5603-84aa-16674faa4f88', '958661e6-226c-5117-9318-5e3265598767', 1, 2, 2, $$Chapter Two: The Weirdo on Maple Street$$, $$The boys bring Eleven to Mike's house, where they disagree on what to do. Mike formulates a plan for Eleven to pretend to be a runaway and seek help from his mother, Karen. Eleven refuses, however, revealing that "bad men" are after her. Will's brother Jonathan visits his estranged father Lonnie in Indianapolis to search for Will, but Lonnie rebuffs him. Hopper's search party discovers a scrap of hospital gown near the lab. After recognizing Will in a photograph and demonstrating her telekinesis, Eleven convinces the boys to trust her, as they believe she can find Will. Using the ''Dungeons & Dragons'' board, Eleven indicates that Will is on the "Upside Down" side of the board and is being hunted by the "Demogorgon" (the creature). Mike's sister Nancy and her friend Barbara 'Barb' Holland go to a party with Nancy's boyfriend Steve Harrington. Searching for Will near Steve's house, Jonathan secretly photographs the party. Joyce receives another call from Will, hears music playing from his stereo, and sees a creature coming through the wall. Left alone by the swimming pool, Barb is attacked by the Demogorgon and vanishes.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('3a95da46-c9bb-58b1-a6c4-8964f15b5815', '958661e6-226c-5117-9318-5e3265598767', 1, 3, 3, $$Chapter Three: Holly, Jolly$$, $$Barb awakens in the Upside Down: a decaying, overgrown alternate dimension. She attempts to escape but is attacked by the Demogorgon. Joyce believes Will is communicating through pulses in light bulbs. Hopper visits Hawkins Lab, and the staff permits him to view doctored security footage from the night Will vanished, leading Hopper to investigate Brenner and discover his involvement with Project MKUltra and that a woman named Terry Ives alleged years earlier that Brenner took her daughter. Eleven recalls Brenner, whom she calls "Papa," punishing her for refusing to hurt a cat telekinetically. Steve destroys Jonathan's camera after discovering the photos from the party. Nancy later recovers a photo of Barb, simultaneously realizing that Barb is missing. Returning to Steve's house to investigate, Nancy finds Barb's untouched Volkswagen and encounters the Demogorgon but manages to escape. Joyce paints an alphabetic board on her wall with Christmas lights, allowing Will to sign to her that he is "RIGHT HERE" and that she needs to "RUN" as the Demogorgon comes through the wall. Believing Eleven knows where Will is, the boys ask her to lead them to him. Eleven leads them, to their frustration, to Will's house. From there, they follow emergency vehicles to a nearby quarry just as Will's body is recovered from the water.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('f1743830-79ae-557a-9565-2cd59ee3f50a', '958661e6-226c-5117-9318-5e3265598767', 1, 4, 4, $$Chapter Four: The Body$$, $$Joyce refuses to believe that the body found at the quarry is Will's. Mike feels betrayed by Eleven until she proves that Will is still alive, channeling his voice through Mike's walkie-talkie. The boys theorize that Eleven could use a ham radio at their school to communicate with Will. Nancy notices a figure behind Barb in Jonathan's photo, which Jonathan realizes matches his mother's description of the Demogorgon. Nancy tells the police about Barb's disappearance. She later fights with Steve, who not only does not care about Barb but only cares about not getting in trouble with his father. Hopper has suspicions regarding the authenticity of the body found in the quarry when he learns that the usual coroner was sent home. Hopper confronts the state trooper who found it and beats him until he admits he was ordered to lie. The boys sneak Eleven into their school to use the radio, while Joyce hears Will's voice through her living room wall. Tearing away the wallpaper, she sees him. Eleven uses the radio to channel Will talking to his mother. Hopper goes to the morgue and finds that the body is a fake, and, suspecting that Brenner is responsible, breaks into the lab.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('9b72c593-bd1a-5b33-9c63-b4c17e55fc75', '958661e6-226c-5117-9318-5e3265598767', 1, 5, 5, $$Chapter Five: The Flea and the Acrobat$$, $$Hopper searches the lab before being knocked out by the lab's guards. The boys ask their science teacher, Mr. Clarke, if it would be possible to travel between alternate dimensions, to which he answers that there could be a theoretical "gate" between dimensions. Hopper awakens at his house and finds a hidden microphone, realizing that Joyce was right the whole time. The boys follow their compasses, searching for a gate that could disrupt the Earth's electromagnetic field. Eleven recalls memories of being placed in a sensory-deprivation tank to telepathically eavesdrop on a Soviet man speaking Russian; while listening, she accidentally came across the Demogorgon. Fearing another encounter with the Demogorgon, Eleven redirects the compasses. Lucas misinterprets this as an act of betrayal, leading Mike and Lucas to fight and Eleven to telekinetically fling Lucas away from Mike. While Dustin and Mike tend to the unconscious Lucas, Eleven runs off. Nancy and Jonathan formulate a plan to kill the Demogorgon. While searching in the woods, they come across a small gate to the Upside Down. Nancy crawls through it but inadvertently draws the Demogorgon's attention. Jonathan unsuccessfully tries to look for Nancy, as the gate to the Upside Down begins to close.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('8b1c49fb-a388-5775-a21a-1911489cf341', '958661e6-226c-5117-9318-5e3265598767', 1, 6, 6, $$Chapter Six: The Monster$$, $$After finding the small gate, Jonathan pulls Nancy back through it. That night, Nancy is afraid to be alone and asks Jonathan to stay in her bedroom. Steve, attempting to reconcile with Nancy, sees them together through her bedroom window and assumes they are in a relationship. Joyce and Hopper track down Terry Ives, who is catatonic and tended by her sister Becky. Becky explains that Terry was a Project MKUltra participant while unknowingly pregnant and that Terry believes Brenner kidnapped her daughter Jane at birth due to her supposed telekinetic and telepathic abilities. Nancy and Jonathan stockpile weapons to kill the Demogorgon, theorizing that it is attracted by blood. Steve is brutally beaten up in a fistfight with Jonathan after he insults Will and calls Nancy a slut. Jonathan is arrested and held at the police station for beating up Steve and inadvertently punching one of the responding officers in the face while Steve's group flees. Eleven walks into a grocery store and shoplifts several boxes of Eggo waffles. Searching for Eleven, Mike and Dustin are ambushed by two bullies, Troy and James, who try to kill Mike. Mike is rescued by Eleven, who uses her powers to break Troy's arm. Eleven collapses and recalls being asked by Brenner to contact the Demogorgon and, in her terror, inadvertently opening the gate. She tearfully admits to Mike and Dustin that she is responsible for allowing the Demogorgon to enter this dimension. Lucas sees agents, who have tracked down Eleven, preparing to ambush Mike's house.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('187e2292-5ad1-5431-8a8a-91e88b3e68dc', '958661e6-226c-5117-9318-5e3265598767', 1, 7, 7, $$Chapter Seven: The Bathtub$$, $$Lucas warns Mike that agents are searching for Eleven. Mike, Dustin, and Eleven flee the house while Brenner and his agents chase the kids using vans. Eleven telekinetically flips one of the vans that block their path as the kids escape. Lucas reconciles with Mike and Eleven, and the kids hide in the junkyard. Nancy and Jonathan reveal their knowledge of the Demogorgon to Joyce and Hopper. Hopper learns from Troy that Eleven is with the kids. The kids, teens, and adults all meet at the Byers' house, where Joyce and Hopper realize that Eleven is Jane Ives. The group asks Eleven to search for Will and Barb telepathically, but her earlier feats have weakened her. They break into the middle school and build a makeshift sensory deprivation tank to amplify Eleven's powers. After telepathically entering the Upside Down again, Eleven finds Barb dead and Will alive, hiding in the Upside Down version of his backyard fort. Realizing that the gate is in the basement of the lab, Hopper and Joyce break into the lab and are apprehended by security guards. Nancy and Jonathan sneak into the police station to retrieve the weapons they purchased previously, planning to lure and kill the Demogorgon. In the Upside Down, the Demogorgon breaks into Will's fort.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('3603c5e5-2ac3-5308-9fb0-af53b14ac058', '958661e6-226c-5117-9318-5e3265598767', 1, 8, 8, $$Chapter Eight: The Upside Down$$, $$Hopper, haunted by the death of his daughter Sara from cancer years earlier, gives up Eleven's location to Brenner, who in exchange allows Hopper and Joyce to enter the Upside Down to rescue Will. Nancy and Jonathan cut their hands to attract the Demogorgon at the Byers' house. Steve, intending to apologize to Jonathan about their fight, arrives just as the Demogorgon appears. Steve, Nancy, and Jonathan fight the Demogorgon and light it on fire, forcing it to retreat back into the Upside Down. Meanwhile, Eleven and the boys hide in the middle school when Brenner and his agents arrive to kidnap Eleven; she kills most of them before collapsing from exhaustion. As Brenner and his remaining agents pin Eleven and the boys down, the Demogorgon appears, attracted by the dead agents' blood, and attacks Brenner and the remaining agents as the boys escape with Eleven. Hopper and Joyce enter the Upside Down's version of the Hawkins library, where they encounter several corpses of the Demogorgon's victims, including Barb, and find Will unconscious with a tendril down his throat. Hopper revives him using CPR after removing the tendril. The Demogorgon corners the kids, but Eleven recovers from her exhaustion and disintegrates it, causing them both to disappear. Will recovers in the hospital, reuniting with his family and friends. One month later, it is Christmas and Nancy is back together with Steve, and both are friends with Jonathan. Will coughs up a slug-like creature and has a vision of the Upside Down, but hides this from his family.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('607d97dd-9e9d-5c01-9272-9eae8aa44aef', '958661e6-226c-5117-9318-5e3265598767', 2, 1, 9, $$Chapter One: MADMAX$$, $$On October 28, 1984, a woman with the power to make people see things and with a tattoo reading "008" on her arm is part of a gang that robs a bank in Pittsburgh, Pennsylvania, and flee the cops using those powers 008 have. Hawkins, Indiana, prepares for Halloween. Maxine "Max" Mayfield, a new girl at school, captures Dustin and Lucas's attention. Joyce is dating her old high school classmate Bob Newby. Hopper investigates a field of mysteriously rotting pumpkins and conspiracy theorist Murray Bauman investigates people who saw Eleven, believing her to be a Russian spy. Mike and Nancy deal with losing Eleven and Barb, and Will has been having apparent hallucinations of the Upside Down, with an enormous, tentacled shadow monster. Joyce and Hopper take Will to Hawkins Lab to the new lab's director, Dr. Sam Owens, who has been giving Will routine medical exams since his return. Owens theorizes that Will's episodes are PTSD brought on by the anniversary of his disappearance. The inter-dimensional gate in the lab's basement has been growing, worrying Owens. Nancy and Steve have dinner with Barb's parents, who still believe their daughter to be missing and who have hired Murray Bauman to find her. Hopper goes home to a cabin in the woods where he secretly lives with Eleven.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('86db15fe-3bf1-5970-9b25-9be1f27f76dd', '958661e6-226c-5117-9318-5e3265598767', 2, 2, 10, $$Chapter Two: Trick or Treat, Freak$$, $$Flashbacks reveal that after killing the Demogorgon, Eleven awoke in the Upside Down. She escaped back into the real world, but hides in the woods after seeing government officials interrogate Mike at his home. In present time, it is Halloween and Eleven asks Hopper if she can go trick-or-treating. Hopper insists that she remain hidden until he and Owens come up with an arrangement that would allow her to live a normal life, which frustrates the homebound Eleven. More pumpkin fields rot across town and Hopper discovers an organic substance in the fields. Nancy wants to tell Barb's parents the truth about her death, but Steve fears that Hawkins Lab could come after them if they tell anyone the truth. They attend a Halloween party where Nancy gets drunk and berates Steve for his lack of empathy for Barb's parents. Before leaving, Steve requests Jonathan to take Nancy home. The boys go trick-or-treating and are later joined by Max. Will has another episode and tells Mike about his visions, leading Mike to admit that he is trying to contact Eleven. Dustin returns home after trick-or-treating and finds a strange creature in his trash can.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('3eec6c59-bcb0-581b-b1f8-670ac870c6a0', '958661e6-226c-5117-9318-5e3265598767', 2, 3, 11, $$Chapter Three: The Pollywog$$, $$Flashbacks reveal that Hopper found Eleven in the woods and agreed to take care of her in his grandfather's old hunting cabin if she agreed not to leave the cabin. In the present, Bob encourages Will to face his fears, not understanding the nature of Will's episodes. Nancy persuades Jonathan to help her tell Barb's parents the truth. They arrange a meeting with Barb's mother in a public park the following day, fearing that Owens may be tapping the phone lines. The creature Dustin found in his trash can is a small, slug-like animal that he names D'Artagnan ("Dart"). He shows Dart to the other kids, and Will concludes that it is from the Upside Down, as it makes a noise similar to one Will heard in his visions. Hopper accuses Owens of failing to keep the gate contained, becoming increasingly concerned about the pumpkin fields. Frustrated with being stuck in the cabin, Eleven leaves to look for Mike; at the school, she sees him arguing with Max but thinks they are flirting. Will suffers from another episode and follows Bob's advice to confront the shadow monster, but it latches to him.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('37f5e788-d718-5079-8588-b3d592ec738a', '958661e6-226c-5117-9318-5e3265598767', 2, 4, 12, $$Chapter Four: Will the Wise$$, $$Joyce and the kids awaken an unconscious Will. Joyce takes Will home, but finds him acting strangely, scribbling furiously on pieces of paper and demanding that the house be kept cold. Eleven returns to the cabin and argues with Hopper over her sneaking out, destroying the cabin's windows in a fit of rage. Joyce calls Hopper and together they discover that Will's scribbles line up. Hopper recognizes that the drawings represent vines, and he leaves. Nancy and Jonathan are captured by Owen's agents when they try to contact Barb's mother and are taken to Hawkins Lab, where Owens shows them the gate to the Upside Down. He admits Barb died in the Upside Down, and says that he wants to prevent foreign governments from learning of it. They are released, and it is revealed that Nancy was secretly recording Owens. An infatuated Lucas tries to get closer to Max, but her violent older stepbrother Billy Hargrove intervenes. While cleaning up her mess the following morning, Eleven finds Hopper's research of her biological mother, Terry Ives, and tries to contact Terry with her powers. A horrified Dustin finds that Dart has broken out of its cage, devoured his pet cat, and is an infant Demogorgon, also known as a Demodog. Hopper digs into one of the pumpkin fields and finds a tunnel resembling the Upside Down.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('a5f09162-6029-5615-9eb7-282679304e7e', '958661e6-226c-5117-9318-5e3265598767', 2, 5, 13, $$Chapter Five: Dig Dug$$, $$Hopper becomes trapped in the tunnels and passes out. Mike sleeps over at the Byers' house to help Will recover. Will has a vision of Hopper, leading Joyce to recruit Bob's help to determine its meaning. Bob identifies Will's drawings as a map of Hawkins and the pumpkin field as the place Hopper was going. Nancy and Jonathan take the tape of Owens' admission to Murray, who realizes the public will not believe the truth and suggests watering it down to make it more palatable. Lucas reveals the truth of Will's disappearance to Max. Dustin traps Dart in his storm cellar and enlists Steve's help to recapture it. Eleven tracks down Terry and Becky Ives. Terry and Eleven are able to communicate using their psychic powers, and Terry reveals to Eleven that she tried to rescue her at the lab and was subjected to a brain-damaging dose of shock therapy by Dr. Brenner. Eleven learns that there was another girl trained like her. Joyce, Bob, Will, and Mike rescue Hopper, and scientists from the lab soon arrive and set the tunnels on fire. As this happens, Will collapses and begins convulsing and screaming in agony.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('61cb51f3-a4ab-5b05-bc2a-309da4859859', '958661e6-226c-5117-9318-5e3265598767', 2, 6, 14, $$Chapter Six: The Spy$$, $$Will is rushed to the lab, demonstrating memory loss. Owens theorizes that the shadow monster is a virus that has spread to Will's brain and is controlling him, and that the creatures from the Upside Down share a hive mind. Therefore, damaging the tunnels will be lethal to the now-infected Will. Nancy and Jonathan spend the night at Murray's, who forces them to admit their feelings for each other. The following morning, the trio send copies of the tape of Owens' admission to numerous newspapers around the country. Nancy and Jonathan discover Will's drawings upon returning to the Byers' house. Lucas and Max regroup with Dustin and Steve, and the group attempt to lure Dart to a junkyard. Max apologizes for being hostile to Lucas, explaining that Billy's violence results from his father getting re-married to Max's mother. Dart arrives in the junkyard flanked by a pack of adolescent monsters. Steve and the kids are cornered until the pack unexpectedly run away. Steve realizes that the Demodogs are being summoned elsewhere. Will discovers a location that the monster prevents him from seeing. Unaware that the monster is manipulating Will, Owens sends a team to investigate. The team is killed by the demodogs, who make their way into the lab.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('124b8cb1-5f3b-55a9-93a0-70d2e6859f41', '958661e6-226c-5117-9318-5e3265598767', 2, 7, 15, $$Chapter Seven: The Lost Sister$$, $$Eleven travels to Chicago, Illinois, and finds the other girl from Terry's memories, named Kali. Realizing they have similar tattoos and were both experimented on by Brenner, Eleven and Kali consider themselves sisters. Kali can project images into people's minds and leads a street gang to seek revenge on Brenner. Eleven tells them that Brenner is dead, so the gang decide to kill the man who tortured Terry instead. Kali helps Eleven hone her abilities by demonstrating that channeling her anger is the key to strengthening her powers. After Eleven uses her powers to find the gang's target, named Ray, the gang travel to Ray's apartment to kill him. Eleven begins to choke Ray with her powers, leading him to reveal that Brenner is still alive. Eleven refuses to kill Ray after seeing a photo of his two young daughters, who are discovered at that same moment to be contacting the police. Eleven stops Kali from killing Ray. The gang flees to the hideout, and Kali insists Eleven either stay and avenge her mother or return to Hawkins. Eleven has a vision of Mike and Hopper's plight at the lab and decides to return while Kali and her gang escape from the police.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('f2da076e-0dd8-5bb2-96e0-6d63d5f245ba', '958661e6-226c-5117-9318-5e3265598767', 2, 8, 16, $$Chapter Eight: The Mind Flayer$$, $$The pack of Demodogs attack the lab, killing all of the scientists minus Dr Owens. Will is sedated, after Mike deduces he is a spy, so that Will doesn't know where they are. Mike, Joyce, Hopper, Bob, Owens, and an unconscious Will escape and take refuge in a room when the power goes out. Bob leaves and manages to restore the power and open the doors. Mike, Hopper, Joyce, and Will escape, with Owens staying to guide Bob. After hiding from a Demodog, a broomstick falls to the floor, triggering a chase by the Demodog. Bob is attacked and killed by a second Demodog as Joyce watches in despair. The group is rescued by Jonathan, Nancy, Steve, and the other children. At the Byers house, they name the monster the "Mind Flayer", who wants to conquer their world and kill them all. They manage to get Will to contact them in Morse code by telling him good memories of his childhood, with Will telling them to close the gate. With a noise, Will detects where he is and sends a Demodog. Eleven arrives and kills the Demodog with her powers and reunites with Mike.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('869362ad-45c4-57c7-ba7d-905beb462439', '958661e6-226c-5117-9318-5e3265598767', 2, 9, 17, $$Chapter Nine: The Gate$$, $$Mike is angry at Hopper for hiding Eleven from him. The group and Eleven come up with a plan to close the gate without killing Will. Hopper and Eleven go to the lab while Joyce, Jonathan, Nancy, and an unconscious Will go to Hopper's cabin to burn the Mind Flayer out from him. Meanwhile, Steve, Mike, Dustin, Max, and Lucas, stay behind to stay safe. Billy arrives to find Max and has a fight with Steve; after Steve was knocked out by Billy, Max sedates Billy and makes him promise to leave them alone. In a cabin, Joyce, Jonathan, and Nancy turn up the heat and successfully drive the Mind Flayer out of Will. While not part of the plan, Steve, Mike, Dustin, Max, and Lucas enter the tunnels and burn the core and attract the demodogs; as they flee, they encounter Dart, who lets them through after Dustin gave it nougat chocolate. Hopper finds Owens injured in the lab. Eleven tries to close the portal and the remaining demodogs try to stop her; Hopper neutralizes them. Eleven manages to close the gate. A month later, Owens facilitates Hopper's adoption of Eleven as Jane Hopper. At the winter formal "Snow Ball", Max and Lucas dance and kiss, as do Mike and Eleven, and Nancy dances with a heartbroken Dustin. In the Upside Down, the Mind Flayer watches the group at Hawkins Middle School.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('de1c7db7-70e1-53f1-aa9a-abc30b14ce8e', '958661e6-226c-5117-9318-5e3265598767', 3, 1, 18, $$Chapter One: Suzie, Do You Copy?$$, $$In June 1984, scientists in the Soviet Union attempt to open a new gate to the Upside Down but fail. One year later, around late June 1985, in Hawkins, the popularity of the new Starcourt Mall has forced many local businesses to close, angering townspeople. Eleven and Mike Wheeler have begun a romantic relationship, much to Jim Hopper's chagrin; he later threatens Mike into agreeing not to see her. Dustin Henderson returns from summer camp and, with Lucas Sinclair's, Max Mayfield's, and Will Byers's help, sets up a radio tower to contact his new girlfriend from camp, Suzie. Dustin's friends leave, and he intercepts a Russian radio transmission. Will senses that the Mind Flayer may still be alive. Rats flock to a mill and explode into an organic mass. Nancy Wheeler and Jonathan Byers work as interns for the Hawkins Post. Nancy experiences sexism from her older male staff. On his way to a rendezvous with Karen Wheeler, Billy Hargrove is run off the road by an unseen creature and dragged inside the mill.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('4cfddc70-e6ff-5f4d-9132-d937b5d0c1c7', '958661e6-226c-5117-9318-5e3265598767', 3, 2, 19, $$Chapter Two: The Mall Rats$$, $$Billy is released from the mill after the creature induces a vision of the Upside Down, which includes a doppelgänger. Following Hopper's threat, Mike lies to Eleven, leading her to seek Max's advice. Dustin reunites with Steve Harrington, who works at the mall's ice cream parlor with Robin Buckley, a former classmate. Nancy and Jonathan investigate the home of Mrs. Driscoll, an elderly woman concerned about rabid rats eating her fertilizer. Eleven and Max bond, going shopping at Starcourt Mall to distract themselves from Mike and Lucas. Tormented by visions and voices, Billy is guided by the creature into kidnapping his fellow lifeguard, Heather Holloway, and bringing her to the creature. Eleven breaks up with Mike after she sees him at the mall and realizes that he has been lying. Joyce tries to figure out why magnets at her home and workplace have stopped working. She goes to the home of Scott Clarke, the kids' science teacher, to ask him why the magnets have stopped functioning, accidentally standing Hopper up for a date. Dustin, Steve, and Robin translate Dustin's intercepted Russian radio message, surmising that it must be a code.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('b9a37be4-0cad-5518-87c7-4a309f2cbdcd', '958661e6-226c-5117-9318-5e3265598767', 3, 3, 20, $$Chapter Three: The Case of the Missing Lifeguard$$, $$While having a sleepover with Max, Eleven jokingly uses her powers to spy on Mike, Lucas, and Will. She later spies on a suspicious and strange Billy, who senses her presence. She and Max discover that Heather has gone missing. Nancy and Jonathan find reports of missing fertilizer and strange behavior among rats across town, and they discover Mrs. Driscoll herself eating fertilizer in her home. After his attempts to play Dungeons and Dragons like old times, Will fights with Mike and Lucas as they are upset over Eleven and Max. He retreats to Castle Byers, and upon recalling his childhood memories with his friends, he destroys it. Robin decodes the Russian communication, which leads to a shipment arriving at Starcourt that night precisely at 21:45; she, Steve, and Dustin spot armed Russian soldiers handling the delivery. Joyce forced Hopper to go to the abandoned Hawkins Lab to answer queries they have about the falling magnets; when they investigate, Hopper is attacked by Grigori, a Russian soldier. Eleven and Max track down Billy and Heather at the home of Heather's parents. After they leave, Billy and Heather subdue her parents, which Will senses while Mike and Lucas find him, and he reveals to them that the Mind Flayer has returned.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('33641532-a8d3-51aa-8c34-996f9c511c87', '958661e6-226c-5117-9318-5e3265598767', 3, 4, 21, $$Chapter Four: The Sauna Test$$, $$Billy and Heather bring her parents to the mill, where they are possessed by the Mind Flayer, now a physical creature composed of flesh from the rats. Hopper recalls Grigori meeting with town mayor Larry Kline; he and Joyce force Kline to reveal that Starcourt Mall is a Russian front for buying abandoned properties across Hawkins. At Starcourt, Dustin, Steve, and Robin, alongside Lucas' sister Erica, discover that the mall's loading dock is an elevator, which traps them beneath the mall. Nancy and Jonathan are fired by their boss Tom, Heather's father, for harassing Mrs. Driscoll; Nancy visits Mrs. Driscoll at the hospital out of suspicion and watches her become possessed by the Mind Flayer. Will reveals his connection with the Mind Flayer to Eleven, Mike, Lucas, and Max, speculating that it has possessed Billy. They devise a plan to trap Billy in the pool's sauna to confirm he is possessed, but Billy escapes and nearly kills them until Eleven subdues him. Billy returns to the mill, where dozens of townspeople have since been possessed by the Mind Flayer.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('7ca24beb-7380-5590-bf25-2ac7ef8592a7', '958661e6-226c-5117-9318-5e3265598767', 3, 5, 22, $$Chapter Five: The Flayed$$, $$Hopper and Joyce search one of the abandoned properties, discovering a hidden laboratory. Grigori arrives to kill them, and they narrowly escape with a hostage–a Russian scientist named Alexei–in tow. Dustin, Steve, Robin, and Erica arrive in a Russian lab underneath Starcourt and hide from Russian soldiers unloading crates from the elevator. Attempting to find a communications room, the group discover a large testing area where scientists try to force open a portal to the Upside Down. As Alexei does not speak English, Hopper and Joyce take him to Murray–the only Russian speaker they know–to translate. Grigori tries to follow them but loses the trail. Nancy and Jonathan regroup with Eleven, Mike, Lucas, Max, and Will and then theorize that Billy and Driscoll are both possessed by the Mind Flayer, who uses them to "flay" (possess) people to create an army. The group decides to visit Mrs. Driscoll at the hospital to learn more but discovers she is missing. They are attacked by Tom and Bruce, who are now part of the Flayed and dissolve into a single organic mass resembling the Mind Flayer after Nancy and Jonathan kill them.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('9e307a36-86d3-5740-afc8-0f6cb6eade1d', '958661e6-226c-5117-9318-5e3265598767', 3, 6, 23, $$Chapter Six: E Pluribus Unum$$, $$Eleven, who had just then reconciled with Mike, uses her powers to incapacitate the bio-massed Mind Flayer, forcing it to flee to the mill. In the Russian lab beneath Starcourt, Steve and Robin are captured, drugged, and interrogated, but Dustin and Erica manage to rescue them. With Murray translating, Hopper and Joyce hold Alexei hostage, forcing him to reveal that the Russians are attempting to access the Upside Down and that they are opening a portal beneath Starcourt. Hopper calls Owens to warn the U.S. Government of the threat, but Joyce insists they return to Hawkins immediately, fearing that their kids may be involved. Grigori corners Kline at Hawkins' Independence Day fair, demanding he step up efforts to find Hopper. Mike argues with Max about relying on Eleven's powers and inadvertently admits his ongoing love for Eleven. To find the Mind Flayer, Eleven uses her powers in an attempt to psychically communicate with Billy, learning of his traumatic childhood and finding the Mind Flayer at the mill. Billy senses Eleven's presence, giving the Mind Flayer access to her location, and reveals that the Mind Flayer plans to kill her to avenge her closing the gate. The Flayed converge on the mill, dissolving into an enormous organic mass and merging with the Mind Flayer.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('ec7924f9-e554-59b4-98f2-edcb8bb552d3', '958661e6-226c-5117-9318-5e3265598767', 3, 7, 24, $$Chapter Seven: The Bite$$, $$Eleven and the others determine that the Mind Flayer is coming for her, since she was the one who previously closed the gate and thus its only threat. Will senses the Mind Flayer approaching. The Mind Flayer attacks the group, and though Eleven defends the others, the Mind Flayer manages to injure her before they flee. Dustin and Erica hide a drugged Steve and Robin in the Starcourt movie theater. Eleven's group breaks into a supermarket to help treat her wounds and gather more supplies. Dustin contacts them over a walkie-talkie to try to explain the situation before he loses battery power. Eleven uses her powers to find Dustin, and the group take off for the mall. Steve admits that he has feelings for Robin, but she comes out to him as a lesbian. Hopper's group make their way to the fairgrounds in Hawkins to find the children, where they are spotted by Kline, who alerts the Russians. Grigori fatally shoots Alexei in front of Murray. Murray, Hopper, and Joyce evade several Soviet agents and learn the agents are looking for the children at the mall. Eleven's group arrive at the mall in time to stop the Russians from shooting Dustin's group. Exhausted and in pain, Eleven collapses, her wound pulsing.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('00892e93-df70-5619-9840-667eebfed38f', '958661e6-226c-5117-9318-5e3265598767', 3, 8, 25, $$Chapter Eight: The Battle of Starcourt$$, $$Eleven rids herself of the piece of the Mind Flayer embedded in her wound, rendering her powerless. Hopper's group arrives, and plans are made to take Eleven's group to safety. At the same time, Hopper, Joyce, and Murray destroy the machine, with Dustin and Erica navigating them from his radio tower. Billy and the Mind Flayer trap Eleven's group at the mall. The others attack the Mind Flayer with fireworks as Eleven frees Billy from its control. Billy sacrifices himself to protect Eleven, Mike, and Max. Hopper fights and kills Grigori, getting trapped with the machine in the process. Out of time, Joyce is forced to trigger an explosion, closing the gate, with Hopper seemingly being disintegrated in the process. The Mind Flayer's physical body dies as Dr. Owens arrives with military forces. Three months later, the deaths are covered up, Starcourt is dismantled, and a disgraced Kline is arrested. The Byers family and a still-powerless Eleven prepare to move out of Hawkins. Eleven confesses her love for Mike and they make plans to meet at Thanksgiving. In Kamchatka, Russian guards are instructed to feed a prisoner, but "not the American", to a captured Demogorgon. }} }} ==Production== ===Development=== Shawn Levy noted in November 2016 that he and the Duffer Brothers had already begun planning a potential third season, saying, "We are not gonna be caught off guard and we don't wanna be making stuff up like the day before we have to write it and make it, so we are definitely optimistic and we have started thinking ahead." The Duffer Brothers anticipated having about four to five seasons to work with, but do want to "have a really finite ending" while the series is still at a height of success, according to Matt, rather than letting it draw out indefinitely. In August 2017, the Duffer Brothers confirmed there would be a third season, with the likelihood of one more season following that, with Ross saying, "We're thinking it will be a four-season thing and then out". However, executive producer Shawn Levy later suggested that either four or five total seasons were possibilities, claiming that "the truth is, we're definitely going four seasons and there's very much the possibility of a fifth. Beyond that, it becomes, I think, very unlikely." Matt Duffer later commented that no official decision has been made, claiming that "It's hard, like four seems short, five seems long. So I don't know what to do." In December 2017, Netflix officially confirmed that they had green lit the third season, consisting of eight episodes. Levy also confirmed that a fourth season was "definitely happening" and that there was potential for a fifth season. A year later, the episode titles for season three were revealed, along with confirming the season would be named ''Stranger Things 3'', similar to the second season. ===Writing=== Writing for the third season began before the second season's premiere, with a good portion being written in twelve-to-fourteen-hour bouts by the series' creators. It was reported that Netflix wanted both the third and fourth seasons to be written simultaneously as to facilitate a back-to-back production schedule, for the actors were aging faster than their on-screen characters, but both the Duffer Brothers and producer Shawn Levy opted to focus only on the third season to ensure it was better-developed and more fleshed out. In terms of narrative, Levy said the season would be less about Will, saying, "We're not going to put Will through hell for a third season in a row. He'll be dealing with stuff, but he won't be at rock bottom... We're [going to be] dealing with forces of evil that are new." David Harbour has said that the third season also draws heavily from the film ''Fletch''. Both Levy and Natalia Dyer echo sentiments that this season's events will be more adult-oriented, with Dyer calling the season's narrative "...Bigger, darker, [and] scarier." The early pitch documents for the season featured a scene that had the Mind Flayer monster rampaging through the Hawkins Fourth of July Parade, but the idea was later scrapped as the scripts were written. In March 2018, it was announced that Priah Ferguson's character had been promoted from a guest role to a recurring role and that Maya Hawke has been cast as Robin, a new lead who's been described as an "alternative girl". Cary Elwes and Jake Busey's castings were announced in April 2018; Elwes was cast as Mayor Kline, a "classic '80s politician – more concerned with his own image than with the people of the small town he governs," and Busey as Bruce, a shifty reporter who works at the ''Hawkins Post''. For the third season, it was reported that several of the cast members would receive pay raises. Ryder and Harbour received an increase to $350,000 an episode from $150,000 and $80,000 respectively; Wolfhard, Matarazzo, McLaughlin, and Schnapp earned a pay increase to over $200,000 an episode, possibly as much as $250,000, a significant increase from the reported $20,000 they had made in season one (later increased by $60,000); and Dyer, Heaton, and Keery received approximately $150,000 an episode. Brown's wage increase was not disclosed but was estimated to be bigger than that of her young counterparts. Some sources suggest she made at least $250,000 and may have received between $300,000 and $350,000 per episode. Jackson, Georgia remained as primary filming area for scenes in Hawkins' downtown area. The major setpiece of the season, Starcourt Mall, was filmed at a re-dressed Gwinnett Place Mall near Duluth, Georgia. The production team had searched around Georgia for a dead mall, one either closed or with significantly reduced vacancy, for film, and found Gwinnett was nearly perfect, having been built in 1984 and thus having the staples of construction from malls in that period. They secured a portion of the mall that had been vacant for some time, redressing the storefronts and food court to feature brands of the 80s, paying attention to which stores likely had made it to Indiana by 1985. Outside "Scoops Ahoy!", a fictional store, they had to make one exception for "Glamour Shots", which was a real chain of photo studios but did not come to malls until after 1985; as a scene of Eleven and Max enjoying a photo shoot was a necessary plot element, the design team created a similar photo studio but with a new fictitious name. Not only did they recreate the facade of each of the storefronts, but they worked to fully stock them as well, in anticipation of any last-minute filming ideas the Duffers may have had. A custom-built grid cloth was employed to completely block sunlight from entering the atrium of the food court to enable filming night scenes during the day. In addition to the aforementioned sets, filming also occurred at pre-existing structures dressed as the Hawkins town hall and Mayor Kline's house. Filming for the third season concluded on November 12, 2018. Regarding the lengthy hiatus between the second and third seasons, Netflix programming executive Cindy Holland noted "[the Duffer Brothers and Shawn Levy] understand the stakes are high. They want to deliver something bigger and better than last year. I think it's going to be a fantastic season. It will be worth the wait." ===Visual effects=== Heading into production for the first season of ''Stranger Things'', the Duffer Brothers intended on shooting a number of special effects using practical methods. However, due to issues with the deployment of the practical effects on-set, coupled with a dissatisfaction with the results of the filmed practical material, The Duffer Brothers became much more keen on utilizing digitally-produced special effects for the second season, and even more so for the third season. During pre-production, the Duffers sat down with Senior VFX Supervisor Paul Graff, production designer Chris Trujillo, and senior concept illustrator Michael Maher to plan out the digital visual effects for the season. One of the most important topics of discussion was the design of the "corporeal" manifestation of the "Shadow Monster/Mindflayer", which the Duffers wanted to be cognizant of the titular "Thing" from John Carpenter's 1982 science fiction horror film ''The Thing''. Like the previous two seasons, the soundtrack was composed by Kyle Dixon and Michael Stein of the electronic band Survive. Legacy Recordings released a 16-track compilation of these songs on July 5, 2019. The finale of the episode "E Pluribus Unum", particularly the scenes involving Eleven's telepathic encounter with the Mind Flayer-possessed Billy, contains excerpts of "Confrontation and Rescue" from the second act of ''Satyagraha'' by Philip Glass. Of note was the use of "The NeverEnding Story", the theme to the 1984 film of the same name, which is used in the final episode when Suzie refuses to provide the critical code until Dustin sings it to her. The Duffers had wanted to introduce Suzie into the show's narrative in some dramatic fashion while giving Matarazzo, who has sung on Broadway before, a chance to show off his own vocals. Initially, they were planning to use "The Ent and the Entwife" song from ''The Lord of the Rings'', but aware that Amazon Studios were developing its own ''Lord of the Rings'' series, decided to change direction. The Duffers credit writer Curtis Gwinn for using "The NeverEnding Story" as the replacement. Matarazzo and Gabriella Pizzolo, the actress playing Suzie and also a seasoned singer on Broadway, were on sets near each other when they sang the song together and were able to harmonize the song as well without the backing music. As their characters were not meant to be in that much synchronization due to being in two different places, the song's backing track and some autotuning were used to blend their singing to their respective settings and the tone of the soundtrack. According to the cast and to composers Kyle Dixon and Michael Stein, the song became an earworm for many of the cast on the day that scene was filmed. ==Marketing== Promotion for the third season began with the first day of production, when Netflix released a video featuring the cast as they met for the season's first script read-through. On July 16, 2018, the first teaser trailer for the season was released. The teaser, which is the first to feature footage shot for the new season, is styled as an in-universe commercial for the newly built Starcourt Mall, one of the main settings for the season's events. The "commercial" lists some of the stores found in the mall as well as restaurants in the "state-of-the-art" food court, and closes with Steve (Joe Keery) and Robin (Maya Hawke) saying "Ahoy!" during a short plug for one of the food court's establishments, an ice cream parlor called Scoops Ahoy. Hours later, the teaser was released online across all of the official ''Stranger Things'' social media accounts. On December 31, pedestrians in New York City's Times Square noticed a video playing on a loop advertising a special announcement "sponsored" by the Starcourt Mall. According to the video, the announcement was slated to be aired on the fictional ABC network affiliate WIYZ. This turned out to be a prelude to the release of stills and the first official trailer the next day on March 20. The trailer quickly became the most-viewed video on Netflix's YouTube channel, amassing 22million views in the first week of its release. On May 21, the first clip from the season was released in tandem with cast posters. The clip, which features Billy flirting with Karen Wheeler at the local pool, includes notable references to the early-1980s comedy films ''Caddyshack'' and ''Fast Times at Ridgemont High''. In July 2019, actors Finn Wolfhard and Caleb McLaughlin took part in a Q&A session at the Open'er Festival in Gdynia, Poland. The festival also boasted a replica of the Palace Arcade filled with retro coin-ops – such as ''Space Invaders'', ''Pac-Man'', ''Donkey Kong'' and ''Dig Dug''. ===Tie-ins=== Netflix revealed they had partnered with around 75 companies to produce tie-in products to promote the third season. For many of these deals, there was no financial exchange between Netflix and the third-parties, with Netflix allowing the third-parties to generate their own marketing buzz for their products while helping to promote ''Stranger Things''. Some of the more notable tie-ins include: * Swedish apparel retailer H&M offered a clothing collection that includes pieces worn on-screen by several of the series' actors on May 24, 2019. The advertisement campaign for the clothing and accessory lines features Dacre Montgomery (Billy) as a model and revolves around his character's summer job as a lifeguard. The unpopular soft drink was released around the time frame of the season's setting, and a number of episodes featured the beverage prominently placed within the frame. were made up into the fictional "Scoops Ahoy!" ice cream parlor in the show for about two weeks. * Fast food chain Burger King started serving special themed 'upside down' Whoppers as a reference to the Upside Down (an alternative universe in the story of the show), including special edition items sold at 11 special locations in the weeks leading up to the premiere, including special ketchup packets displaying a nose in reference to the nose bleeding of the character, Eleven. Burger King also promoted their restaurant commercials, cups and boxes in a special 1980s theme as a tie-in with Coca-Cola. The restaurant was also featured in the food court of the Starcourt Mall. * In the week leading to ''Stranger Things 3''s release, Microsoft teased "Windows 1.0", the company's first graphic operating system introduced in 1985. Microsoft released this mock version of "Windows 1.0" as an app for Windows 10 on July 8, 2019. The app features a similar interface as the original software, with various Easter eggs to the television series scattered through the app. * Netflix partnered with Epic Games to include ''Stranger Things'' tie-ins into ''Fortnite Battle Royale'' around the premiere of the third season. ==Video game== A video game adaptation titled ''Stranger Things 3: The Game'' was released hours after the third season premiered on July 4, 2019. It was developed by BonusXP and published by Netflix The game was criticized by reviewers for being an exact scene-by-scene replica of the season. ==Reception== ===Audience viewership=== ====Netflix ratings==== Within four days of its release, Netflix reported that over 40.7million accounts had seen at least 70% of one episode of the third season, a record viewership for any Netflix program, while 18.2million had seen the entire season within the time. Netflix reported in October 2019 that over 64million households had watched ''Stranger Things 3'' within the first four weeks of its release. ====Nielsen ratings==== Nielsen ratings recorded viewership data for those who viewed the series within the United States on a TV set; the data does not account for mobile, tablet, and PC devices, nor viewers outside of the United States. {| class="wikitable sortable" style="text-align:center;$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('17cf1fd0-ff94-51e7-b0df-e09c546b8730', '958661e6-226c-5117-9318-5e3265598767', 4, 1, 26, $$Chapter One: The Hellfire Club$$, $$In a flashback to 1979, Dr. Brenner is experimenting on children with supernatural abilities until a mysterious incident kills all the children except Eleven. In 1986, eight months after the events at Starcourt Mall, Joyce, Will, Jonathan, and Eleven have moved to California, where Eleven struggles with the loss of her powers and is routinely bullied by other students. Joyce receives a porcelain doll in the mail, seemingly from Russia, and finds a hidden note stating that Jim Hopper is alive. In Hawkins, Mike and Dustin have joined their high school's "Hellfire Club," a Dungeons & Dragons club run by the iconoclastic Eddie Munson. As a result, they miss seeing Lucas win the basketball team's championship. Max, who broke up with Lucas, struggles to grieve Billy's death. Chrissy Cunningham, a student on the cheerleading squad, is tormented by visions of her abusive mother and a ticking grandfather clock. While buying drugs from Eddie, Chrissy is possessed and killed by a sentient humanoid creature from her visions.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('e29a85e8-f381-51bc-8295-a4c9fb98a1e9', '958661e6-226c-5117-9318-5e3265598767', 4, 2, 27, $$Chapter Two: Vecna's Curse$$, $$Hopper survived the explosion beneath the Starcourt Mall, but was captured by Soviet soldiers and sent to a prison camp in Kamchatka. Joyce and Murray call the phone number listed on the note they sent him and speak to Dmitri Antonov, a prison guard Hopper has bribed. Antonov asks them to deliver a $40,000 ransom to his contact in Alaska. Mike flies to California to visit Eleven, where he and Will witness her classmate Angela bullying her; Eleven eventually retaliates by hitting Angela in the face with a skate. Max tells Dustin that she saw Eddie fleeing the night Chrissy died. Along with Robin and Steve, they track down the traumatized Eddie and explain the Upside Down to him. Eddie and Dustin dub the entity that killed Chrissy "Vecna." Nancy and her fellow journalist Fred investigate Chrissy's death; Eddie's uncle Wayne tells Nancy he believes the killer is Victor Creel, a Hawkins resident who was institutionalized after allegedly murdering his family in the 1950s. Fred is lured to the woods by visions of a student he accidentally killed before Vecna murders him.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('b241d564-53f9-57fd-b2c6-806593f4a701', '958661e6-226c-5117-9318-5e3265598767', 4, 3, 28, $$Chapter Three: The Monster and the Superhero$$, $$Sam Owens is visited by U.S. Army Lieutenant Colonel Jack Sullivan, who believes Eleven is responsible for Chrissy's death. Eleven is arrested for assaulting Angela, but Owens takes her away, explaining that Hawkins is in grave danger and that he has been working on a program to help Eleven regain her powers. Eleven agrees to go with him. Joyce and Murray fly to Alaska to deliver Hopper's ransom. Hopper bribes a fellow inmate to break his shackles with a sledgehammer. Nancy and Robin go to the library to research Victor Creel and discover that Creel believes his family's murders were committed by a demon, which they believe to be Vecna. Chrissy's boyfriend Jason leads the basketball team to hunt for Eddie, whom he believes is Chrissy's murderer, but Lucas abandons them when Jason becomes violent. Max remembers that Chrissy had visited the school counselor before being killed by Vecna. She steals Chrissy and Fred's files from the counselor's office and discovers they suffered from post-traumatic stress disorder symptoms similar to her own. Max hears Vecna call her by name and hallucinates a grandfather clock.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('68d6d686-1cfc-564d-8ed5-c0ac858881e2', '958661e6-226c-5117-9318-5e3265598767', 4, 4, 29, $$Chapter Four: Dear Billy$$, $$Joyce and Murray deliver the ransom payment to Antonov's contact, Yuri, but he drugs them and plans to hand them (and Hopper and Antonov) over to the Russians for a larger profit. Hopper escapes from the prison camp but is soon recaptured. Jonathan, Mike, and Will prepare to escape from Wallace and Harmon, agents sent by Owens to watch them, but armed soldiers attack the house. They escape with the help of Jonathan's friend Argyle, bringing the wounded Harmon with them. Nancy and Robin interview the imprisoned Victor Creel, who recounts how his family was tormented and killed by supernatural forces while he was being arrested for their murders. Max, fearing that Vecna is about to kill her, writes letters to her friends and family and goes to the cemetery to read Billy's letter at his gravestone. She is soon possessed by Vecna and finds herself at an altar within her mind. Steve, Dustin, and Lucas learn from Nancy and Robin that playing music can break Vecna's spell, and they put Max's favorite song, "Running Up That Hill," on a cassette tape. This opens a portal through which Max narrowly escapes Vecna's control.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('b431d758-7c0a-5af2-b53a-34b7bf8feadd', '958661e6-226c-5117-9318-5e3265598767', 4, 5, 30, $$Chapter Five: The Nina Project$$, $$Owens takes Eleven to an abandoned ICBM silo in Nevada, where he and Dr. Brenner have developed a specialized isolation tank (called "NINA") that will allow Eleven to access memories of her time with other kids at Hawkins Lab. After her first time in the tank, Eleven tries to escape and briefly regains her powers in the process, convincing her to continue the experiment. In California, before dying, Agent Harmon gives the kids a pen containing a phone number for Project NINA that connects to a modem; Mike decides to enlist the help of Dustin's girlfriend, Suzie, in Salt Lake City. After Yuri's betrayal, Hopper is imprisoned along with Antonov. While flying to Russia, Joyce and Murray subdue Yuri and crash in the desert. Max, Lucas, Steve, and Dustin reunite with Nancy and Robin and investigate the Creel house. Inside, they encounter flickering lights, which they attribute to Vecna's movements in the Upside Down. Jason and his teammates locate Eddie attempting to escape in a boat on Lover's Lake; Jason and Patrick swim after him. In the water, Vecna kills Patrick in front of Jason and Eddie.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('fa2d697b-9558-5182-b7b0-4876a52cc7fc', '958661e6-226c-5117-9318-5e3265598767', 4, 6, 31, $$Chapter Six: The Dive$$, $$Eleven relives memories of befriending a lab nurse, who warns her not to trust Brenner. She also recalls being threatened by other test subjects, leading her to believe she was responsible for the lab massacre. Suzie helps Mike's group locate the coordinates for Project NINA. Hopper and the other inmates are given a large feast, which Hopper attributes to the Russians preparing to feed them to the Demogorgon. He later manages to steal a lighter, remembering that the Demogorgon's weakness is fire. Joyce and Murray force Yuri to take them to a nearby town where he stores his belongings and decide that Murray will impersonate Yuri to infiltrate the prison. Jason galvanizes the residents of Hawkins at a town hall meeting against Eddie's alleged Satanic cult, the "Hellfire Club." The Hawkins group finds Eddie; Dustin notices his compass is malfunctioning and realizes there must be a new portal to the Upside Down nearby. They trace the portal to Lover's Lake, where Steve dives in to inspect it before being pulled into the Upside Down by a tendril and surrounded by bat-like creatures; Nancy, Robin, and Eddie jump in after him.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('db6e2b37-9b82-528e-930d-fd1c3efa3543', '958661e6-226c-5117-9318-5e3265598767', 4, 7, 32, $$Chapter Seven: The Massacre at Hawkins Lab$$, $$Joyce, Murray, and Yuri enter Kamchatka and witness Hopper and his fellow inmates fighting the Demogorgon. Hopper stops the creature with a flaming spear while Murray and Joyce subdue the guards and open the prison gates, allowing Hopper and Antonov to escape. Joyce and Hopper are reunited. Dustin, Lucas, and Erica theorize that Vecna has created a portal at the site of each murder, which they communicate to the older teens in the Upside Down. Both groups meet inside Eddie's trailer at the gate where Chrissy died. Robin and Eddie emerge unharmed, but Vecna possesses Nancy. She discovers that he is Victor Creel's son, Henry, who killed his mother and sister with his psychokinetic powers before falling into a coma and being placed in Brenner's care. Henry became Subject 001 in Brenner's attempts to replicate his powers and later the orderly whom Eleven befriended. Eleven finally remembers that Henry committed the lab massacre and tried to kill her when she refused to help fulfill his murderous ambitions; Eleven overpowered Henry and sent him to the Upside Down where he eventually became Vecna.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('f23c173f-56c8-581d-b989-230a2fd96fba', '958661e6-226c-5117-9318-5e3265598767', 4, 8, 33, $$Chapter Eight: Papa$$, $$Vecna shows Nancy, who is still possessed by him, a vision of the future in which Hawkins is torn apart by rifts before freeing her. The group determines that Vecna needs four portals to implement his plan; Max volunteers to lure Vecna into possessing her so the others can attack him while he's distracted. Eleven, using her powers, learns of this plan and gets Owens to arrange transit to Hawkins. However, Brenner betrays and secures Owens and traps Eleven, insisting she needs to complete her training. Eleven realizes that Brenner had been using her for years to try to retrieve Henry from the Upside Down. Sullivan and his forces arrive and kill all the staff; Brenner escapes with Eleven, but is shot himself. Sullivan's crew tries to kill Eleven from a helicopter, but she uses her powers to eliminate them just as the California group arrives. As Brenner bleeds out in her arms, he asks for her forgiveness; Eleven silently leaves him to die. In Russia, Hopper, Joyce, Murray, Yuri, and Antonov escape the base after discovering several more creatures from the Upside Down, as well as a shadowy fragment of the Mind Flayer, which is being studied at the prison.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('187e85c2-ad20-529a-9ba3-a225f537526e', '958661e6-226c-5117-9318-5e3265598767', 4, 9, 34, $$Chapter Nine: The Piggyback$$, $$The Hawkins group puts their plan into action: Max, Lucas, and Erica go to the Creel House while Steve, Nancy, and Robin go to its Upside Down counterpart to attack Vecna, with the bats being lured by Dustin and Eddie. Eddie sacrifices himself in the process. Eleven's group creates an isolation tank so she can enter Max's mind and fight Vecna. However, Vecna overwhelms her and possesses Max, revealing to Eleven that he has controlled the Upside Down since she sent him there. Mike professes his love for Eleven, giving her the strength to break Vecna's control over Max, but after Jason interferes, Max dies from her injuries. Hopper, Joyce, and Murray re-enter the prison and kill the remaining Demogorgons, weakening Vecna. Steve, Robin, and Nancy set fire to Vecna's physical form and shoot him, seemingly killing him. Eleven uses her powers to revive Max, but Max's brief death allows Vecna's portals to open and pass through Hawkins, killing Jason. Two days later, the town recovers from an "earthquake." Everyone unites, while Max remains in a coma. Will senses that Vecna is still alive, and the Upside Down begins to invade Hawkins.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('e60a9c77-b126-5fed-baae-2b7ae45d0570', '958661e6-226c-5117-9318-5e3265598767', 5, 1, 35, $$Chapter One: The Crawl$$, $$While hiding in the Upside Down in 1983, Will is caught by a Demogorgon and is brought to Vecna, who infects Will with a tentacle. In 1987, 19 months after the Rifts incident, a contingent of the US military, led by Dr. Kay and Lt. Robert Akers, have placed Hawkins under quarantine and created a base camp within the Upside Down while still on the hunt for Eleven, who trains in hiding with Hopper and Joyce. Will, Lucas, and Mike lay low, though Dustin provokes the school basketball team by continuing to honor Eddie. Steve, Robin, Jonathan, and Nancy work at WSQK, a local radio station, where they relay coded messages to the group about opportunities to sneak Hopper into the Upside Down, which they call "crawls", to find Vecna's hideout. Dustin is viciously beaten at Eddie's grave, causing him to miss the next crawl, which goes awry when a Demogorgon attacks a military caravan, forcing Hopper to take shelter within the Upside Down. Will telepathically witnesses the attack and sees the Demogorgon head towards the Wheeler residence just as it tears open a gate in the bedroom of Mike and Nancy's younger sister Holly.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('fd79cad8-8277-52c8-8234-41351b5ddb98', '958661e6-226c-5117-9318-5e3265598767', 5, 2, 36, $$Chapter Two: The Vanishing of Holly Wheeler$$, $$The Demogorgon attacks and severely injures Mike and Nancy's parents, Karen and Ted, before disappearing with Holly to the Upside Down. Eleven follows the Demogorgon through a gate into the Upside Down and finds Hopper. The two then search for Holly until they encounter a giant wall surrounding the edge of Hawkins. Jonathan accuses Steve of competing for Nancy's attention before a bloodied Dustin finds them, while Lucas continues tending to a comatose Max in hopes she will wake up. As Karen and Ted remain hospitalized, Nancy and Mike theorize that "Mr. Whatsit", Holly's imaginary friend, may be real and involved in Holly's disappearance. Robin proposes using Will's telepathic link to Vecna's hive mind to track Holly in the Upside Down. Karen informs Nancy and Mike that Mr. Whatsit's first name is Henry, whom they realize is Vecna's human form, Henry Creel. Will discovers that his earlier visions were actually from Henry's point of view as he stalked Holly, realizing he can know Henry's targets before they are taken.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('98d63ee7-f1c0-51b0-8ad1-72782c3998e1', '958661e6-226c-5117-9318-5e3265598767', 5, 3, 37, $$Chapter Three: The Turnbow Trap$$, $$Henry targets Holly's classmate and bully, Derek Turnbow, as his next victim. Hopper and Eleven fail to break through the massive wall and are ambushed by soldiers, but manage to overpower them. Hopper and Eleven interrogate Akers, concluding that Dr. Kay is holding Henry at the base. Will, Nancy, and Mike inform the group that Henry lured Holly by claiming he was her imaginary friend, prompting them to devise a plan to use Derek as bait to trap the Demogorgon, and implant a tracker in it to reach Holly before more children are taken. The group arms themselves using weapons smuggled in by Murray and enlists Erica to drug Derek and his family. The team splits up, transporting the unconscious family to an abandoned barn while converting Derek's house into a trap for the Demogorgon. The plan unravels when Derek wakes up and Will realizes the Demogorgon has located his group. Meanwhile, Holly finds herself in Henry's childhood home. In the nearby forest, she encounters Max.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('7f8a8551-6e38-5588-ad7c-57be49690485', '958661e6-226c-5117-9318-5e3265598767', 5, 4, 38, $$Chapter Four: Sorcerer$$, $$Hopper and Eleven infiltrate the military base, intending to kill Henry. They defeat Dr. Kay and her soldiers, discovering that the captive inside is Eleven's adoptive sister, Kali. Max explains to Holly that they are trapped inside a psychic realm made of Henry's memories, nicknamed "Camazotz" by Holly, where Max has remained ever since her brief death. Will's group is attacked by a Demogorgon until Dustin, Steve, Nancy, and Jonathan chase it into the Upside Down. Meanwhile, the military detains children in Hawkins who could be potential victims. Will experiences a vision of Holly and three other children being restrained by tentacles in Vecna's lair, with empty spots for eight more. Will's group infiltrates the base to smuggle the children out of Hawkins. However, Henry, in his Vecna form, and three Demogorgons emerge from the Upside Down, slaughter most of the soldiers at the Hawkins base, and kidnap Henry's targets, including Derek. Before retreating into the Upside Down, Henry tells Will that he intends to use the children, whom he calls "perfect vessels", to reshape the world. Will then unlocks psychic abilities and kills the Demogorgons to save Mike, Lucas, and Robin.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('48631bf7-0083-5c23-94af-376fc55c8226', '958661e6-226c-5117-9318-5e3265598767', 5, 5, 39, $$Chapter Five: Shock Jock$$, $$In Camazotz, the kidnapped children awaken, and while most believe Henry's claim that he saved them, Holly and Derek do not. Max and Holly traverse Henry's memories of Holly to search for an escape as Derek distracts him. Henry discovers the plan, threatens Derek's family, turns into Vecna, finds Holly, and strangles Max. Will's group reanimates a dead Demogorgon using the radio tower's voltage so Will can reconnect to the hive mind and kill Vecna. Will possesses Vecna's body, breaking his leg and speaking through him to tell Max and Holly to run; Henry expels him from his mind soon after, causing Will to pass out. In the Upside Down, Hopper and Eleven escape the military base with Kali, who reveals Dr. Kay was using her blood, just as Dr. Brenner used Henry's blood, in failed experiments to give children powers. At Hawkins Lab, Dustin theorizes that the wall surrounding the Upside Down is a protective shield that, if destroyed, can weaken Henry. Nancy and Jonathan find a mysterious sphere on the roof of the lab. Dustin finds Brenner's journal and realizes he is wrong, but fails to warn the others before Nancy shoots the sphere.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('d6d3e77d-6d63-5ab4-ad6a-e90374aa97b5', '958661e6-226c-5117-9318-5e3265598767', 5, 6, 40, $$Chapter Six: Escape from Camazotz$$, $$Dustin explains to Steve that the Upside Down is not an alternate dimension but a wormhole to another realm, held together by a mass of "exotic matter", which they realize is the sphere on the roof. The exotic matter detonates upon being shot, causing the building to begin melting; Nancy and Jonathan become trapped in a collapsing room. Believing they will die, they end their relationship on good terms; the melting eventually halts. Max and Holly find a memory of a young Henry killing a man in self-defense in a cave. Erica and Murray recruit Mr. Clarke to help locate Dustin's group. Henry uses the unconscious Will to track Max in the real world and sends Demodogs to kill her at the hospital. Hopper, Eleven, and Kali reunite with the others in Hawkins, and Eleven frees Will. At the hospital, Lucas, Robin, and her girlfriend Vickie protect Max from the Demodogs, with Karen ultimately saving them by detonating a laundry machine to kill the creatures. Seeing her exit from Vecna's mind formed via Lucas's music, Max tells Holly she needs to find her own way out and reminds her of her past bravery, allowing both to escape separately.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('69761944-eafa-5b29-bf88-7a549cdffabe', '958661e6-226c-5117-9318-5e3265598767', 5, 7, 41, $$Chapter Seven: The Bridge$$, $$Max awakens safely in the real world, while Holly awakens inside Vecna's lair and escapes through a gate, falling through the Upside Down before being pulled back by Vecna. Erica, Murray, and Mr. Clarke map Dustin's location in the Upside Down to the lab, and Eleven opens a rift so the group can reunite. Dustin deduces that the Upside Down was created when Brenner forced Eleven to contact Henry, and now serves as a bridge to a separate realm, "the Abyss", which Henry plans to merge with their world, likely that night. The group decides to let Henry draw the worlds close enough to climb the WSQK radio tower into the Abyss, rescue the children, and then destroy the Upside Down by detonating a time bomb near the exotic matter to stop the worlds from merging. Max volunteers to guide Eleven through Henry’s mind, and Kali insists on joining. Will comes out as gay to the group, reasoning that confronting his fears weakens Vecna's hold. Henry manipulates the kidnapped children into turning against Holly; she is forced to join hands with the children and Henry, who puts them in a trance.$$);
INSERT INTO episode (id, show_id, season, episode_number, episode_index, title, summary) VALUES ('a670341e-531c-5e3a-9c30-bc26e8c6c607', '958661e6-226c-5117-9318-5e3265598767', 5, 8, 42, $$Chapter Eight: The Rightside Up$$, $$As the others make their way to the Abyss, Eleven, Kali, and Max enter Henry's mind and stop him from merging the worlds, but he transforms into Vecna, escapes, and tricks Hopper into breaking the link. Akers' forces assault the lab and kill Kali; Eleven kills them in return. Holly leads the other children out of Henry's mind while Eleven enters the Abyss to fight Henry. Will witnesses Henry's past and learns he was corrupted by a fragment of the Mind Flayer, which he fully embraces despite Will's pleas. The Mind Flayer rises as a giant kaiju, which the group kills while Eleven and Will overpower Henry. The group rescues the children, and Joyce decapitates a dying Henry. Upon returning to Hawkins and detonating the bomb they placed in the Upside Down, the group is arrested by Dr. Kay, but is then released when Eleven chooses to stay behind in the collapsing Upside Down. 18 months later, life returns to normal; the young adults reunite, Hopper proposes to Joyce, and the party graduates and finishes a ''Dungeons & Dragons'' campaign. Mike imagines their futures and theorizes how Eleven may still be alive, with the others choosing to believe him.$$);
